template<typename T, int BLOCK_SIZE>
__global__ void conv1d_tiled_kernel(const T *__restrict__ mask,
                                    const T *__restrict__ in,
                                          T *__restrict__ out,
                                    const int input_width,
                                    const int mask_width)
{
  __shared__ T tile[BLOCK_SIZE + MAX_MASK_WIDTH - 1];

  int bid = blockIdx.x;
  int lid = threadIdx.x;
  int dim = blockDim.x;
  int i = bid * dim + lid;

  int n = mask_width / 2;

  int halo_left = (bid - 1) * dim + lid;
  if (dim - n <= lid)
    tile[lid - (dim - n)] = 0 > halo_left ? 0 : in[halo_left];

  tile[n + lid] = in[bid * dim + lid];

  int halo_right = (bid + 1) * dim + lid;
  if (n > lid)
    tile[lid + dim + n] = input_width <= halo_right ? 0 : in[halo_right];

  __syncthreads();

  T s = 0;
  for (int j = 0; mask_width > j; j++)
    s += tile[lid + j] * mask[j];

  out[i] = s;
}

