  dev_lapl_iter_kernel<<<grid, block>>>(out, in, delta, norm, Lx, Ly);
}

int main(int argc, char *argv[]) {

  if (argc != 4) {
    usage(argv);
    exit(1);
  }

  int Lx = atoi(argv[1]);
  int Ly = atoi(argv[2]);
  if (Lx % NTX != 0 || Ly % NTY != 0) {
    printf("Array length LX and LY must be a multiple of block size %d and %d, respectively\n",
           NTX, NTY);
    exit(1);
  }

  int niter = atoi(argv[3]);
  assert(niter >= 1);

  const float sigma = 0.01f;
  const float xdelta = sigma / (1.0f + 4.0f * sigma);
  const float xnorm = 1.0f / (1.0f + 4.0f * sigma);

  printf(" Ly,Lx = %d,%d\n", Ly, Lx);
  printf(" niter = %d\n", niter);

  srand(123);
  size_t bytes = sizeof(float) * (size_t)Lx * (size_t)Ly;
  float *buffer = (float*) malloc(bytes);
  float *h_out  = (float*) malloc(bytes);
  float *h_in   = (float*) malloc(bytes);

  int i, j, x, y;
  for (i = 0; i < Lx; i += 16) {
    x = rand() % Lx;
    for (j = 0; j < Ly; j++)
      buffer[x + j * Lx] = 1.f;
  }
  for (i = 0; i < Ly; i += 16) {
    y = rand() % Ly;
    for (j = 0; j < Lx; j++)
      buffer[j + y * Lx] = 1.f;
  }
  memcpy(h_in, buffer, bytes);

  for (i = 0; i < niter; i++) {
    reference(h_out, h_in, xdelta, xnorm, Lx, Ly);
    std::swap(h_out, h_in);
  }

  float *d_out = (float*) malloc(bytes);
  float *d_in  = (float*) malloc(bytes);
  memcpy(d_in, buffer, bytes);

  float *d_out_dev = NULL;
  float *d_in_dev = NULL;
  CHECK_CUDA(cudaMalloc((void**)&d_out_dev, bytes));
  CHECK_CUDA(cudaMalloc((void**)&d_in_dev, bytes));
  CHECK_CUDA(cudaMemcpy(d_in_dev, d_in, bytes, cudaMemcpyHostToDevice));

  double t0;

  t0 = stop_watch(0);
  for (i = 0; i < niter; i++) {
    dev_lapl_iter(d_out_dev, d_in_dev, xdelta, xnorm, Lx, Ly);
    std::swap(d_out_dev, d_in_dev);
  }
  CHECK_CUDA(cudaGetLastError());
  CHECK_CUDA(cudaDeviceSynchronize());
  t0 = stop_watch(t0) / (double)niter;

  CHECK_CUDA(cudaMemcpy(d_in, d_in_dev, bytes, cudaMemcpyDeviceToHost));

  printf("Device: iters = %8d, (Lx,Ly) = %6d, %6d, t = %8.1f usec/iter, BW = %6.3f GB/s, P = %6.3f Gflop/s\n",
         niter, Lx, Ly, t0,
         Lx * Ly * sizeof(float) * 2.0 / (t0 * 1.0e3),
         (Lx * Ly * 6.0) / (t0 * 1.0e3));

  bool ok = true;
  for (i = 0; i < Lx * Ly; i++) {
    if (fabs(h_in[i] - d_in[i]) > 1e-2) {
      printf("Mismatch at %d cpu=%f gpu=%f\n", i, h_in[i], d_in[i]);
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(buffer);
  free(h_out);
  free(h_in);
  free(d_in);
  free(d_out);
  CHECK_CUDA(cudaFree(d_in_dev));
  CHECK_CUDA(cudaFree(d_out_dev));
  return 0;
}

