bool within_epsilon(float* output, float* reference, const size_t dimx,
                    const size_t dimy, const unsigned int radius,
                    const float delta = 0.01f) {
  FILE* fp = std::fopen("./error_diff.txt", "w");
  if (!fp) fp = stderr;

  bool error = false;
  double norm2 = 0;

  for (size_t iy = 0; dimy > iy; iy++) {
    for (size_t ix = 0; dimx > ix; ix++) {
      if (radius <= ix && (dimx - radius) > ix && radius <= iy &&
          (dimy - radius) > iy) {
        float difference = std::fabs(*reference - *output);
        norm2 = norm2 + (difference * difference);
        if (delta < difference) {
          error = true;
          std::fprintf(fp, " ERROR: (%zu,%zu)\t%e instead of %e (|e|=%e)\n", ix, iy,
                       *output, *reference, difference);
        }
      }

      ++output;
      ++reference;
    }
  }

  if (stderr != fp) std::fclose(fp);
  norm2 = std::sqrt(norm2);
  if (error) std::printf("error (Euclidean norm): %.9e\n", norm2);
  return error;
}

