__global__ void jacobi_kernel(const float* __restrict__ f_old,
                              float* __restrict__ f,
                              float* error) {
  __shared__ float sdata[256];

  const int tx = threadIdx.x;
  const int ty = threadIdx.y;
  const int tid = ty * blockDim.x + tx;

  const int i = 1 + blockIdx.x * blockDim.x + tx;
  const int j = 1 + blockIdx.y * blockDim.y + ty;

  float local = 0.0f;

  if (i <= N - 2 && j <= N - 2) {
    float t = 0.25f * (f_old[IDX(i - 1, j)] +
                       f_old[IDX(i + 1, j)] +
                       f_old[IDX(i, j - 1)] +
                       f_old[IDX(i, j + 1)]);
    float df = t - f_old[IDX(i, j)];
    f[IDX(i, j)] = t;
    local = df * df;
  }

  sdata[tid] = local;
  __syncthreads();

  for (int stride = 128; stride > 0; stride >>= 1) {
    if (tid < stride) {
      sdata[tid] += sdata[tid + stride];
    }
    __syncthreads();
  }

  if (tid == 0) {
    atomicAdd(error, sdata[0]);
  }
