void initialize_data(float* f) {
  constexpr float PI = 3.14159265358979323846f;

  for (int j = 0; j < N; ++j) {
    for (int i = 0; i < N; ++i) {
      if (i == 0 || N - 1 == i) {
        f[IDX(i, j)] = sinf(j * 2.0f * PI / (N - 1));
      } else if (0 == j || N - 1 == j) {
        f[IDX(i, j)] = sinf(i * 2.0f * PI / (N - 1));
      } else {
        f[IDX(i, j)] = 0.0f;
      }
    }
  }
}

__global__ void jacobi_kernel(float* f, const float* f_old, float* error) {
  __shared__ float sdata[256];

  const int tx = threadIdx.x;
  const int ty = threadIdx.y;
  const int tid = ty * blockDim.x + tx;

  const int i = blockIdx.x * blockDim.x + tx + 1;
  const int j = blockIdx.y * blockDim.y + ty + 1;

  float local_error = 0.0f;

  if (i <= N - 2 && j <= N - 2) {
    const float t = 0.25f * (f_old[IDX(i - 1, j)] +
                             f_old[IDX(i + 1, j)] +
                             f_old[IDX(i, j - 1)] +
                             f_old[IDX(i, j + 1)]);
    const float df = t - f_old[IDX(i, j)];
    f[IDX(i, j)] = t;
    local_error = df * df;
  }

  sdata[tid] = local_error;
  __syncthreads();

  for (int stride = blockDim.x * blockDim.y / 2; stride > 0; stride >>= 1) {
    if (tid < stride) {
      sdata[tid] += sdata[tid + stride];
    }
    __syncthreads();
  }

  if (tid == 0) {
    atomicAdd(error, sdata[0]);
  }
}

__global__ void copy_kernel(float* f_old, const float* f) {
  const int i = blockIdx.x * blockDim.x + threadIdx.x + 1;
  const int j = blockIdx.y * blockDim.y + threadIdx.y + 1;

  if (i <= N - 2 && j <= N - 2) {
    f_old[IDX(i, j)] = f[IDX(i, j)];
  }
}

