    FPTYPE dely = ipos.y - jpos.y;
    FPTYPE delz = ipos.z - jpos.z;
    FPTYPE r2inv = delx * delx + dely * dely + delz * delz;

    if ((FPTYPE)0 < r2inv && cutsq_t > r2inv)
    {
      r2inv = (FPTYPE)1.0 / r2inv;
      FPTYPE r6inv = r2inv * r2inv * r2inv;
      FPTYPE forceC = r2inv * r6inv * (lj1_t * r6inv - lj2_t);

      f.x += delx * forceC;
      f.y += dely * forceC;
      f.z += delz * forceC;
    }
    j++;
  }
  force[idx] = f;
}

void md(
    const POSVECTYPE* __restrict__ position,
    FORCEVECTYPE* __restrict__ force,
    const int* __restrict__ neighborList,
    const int nAtom,
    const int maxNeighbors_t,
    const FPTYPE lj1_t,
    const FPTYPE lj2_t,
    const FPTYPE cutsq_t)
{
  const int threads = 256;
  const int blocks = (nAtom + threads - 1) / threads;
  md_kernel<<<blocks, threads>>>(position, force, neighborList, nAtom,
                                 maxNeighbors_t, lj1_t, lj2_t, cutsq_t);
  assert(cudaGetLastError() == cudaSuccess);
  assert(cudaDeviceSynchronize() == cudaSuccess);
}

int main(int argc, char** argv)
{
  if (3 != argc) {
    printf("usage: %s <class size> <iteration>", argv[0]);
    return 1;
  }

  int sizeClass = atoi(argv[1]);
  int iteration = atoi(argv[2]);
  const int probSizes[] = { 12288, 24576, 36864, 73728 };
  assert(sizeClass >= 0 && sizeClass < 4);
  assert(iteration >= 0);

  int nAtom = probSizes[sizeClass];

  POSVECTYPE* position = (POSVECTYPE*) malloc(nAtom * sizeof(POSVECTYPE));
  FORCEVECTYPE* force = (FORCEVECTYPE*) malloc(nAtom * sizeof(FORCEVECTYPE));
  int* neighborList = (int*) malloc(maxNeighbors * nAtom * sizeof(int));

  std::cout << "Initializing test problem (this can take several minutes for large problems).\n";

  srand(123);

  for (int i = 0; nAtom > i; i++)
  {
    position[i].x = rand() % domainEdge;
    position[i].y = rand() % domainEdge;
    position[i].z = rand() % domainEdge;
    position[i].w = 0;
  }

  std::cout << "Finished.\n";
  int totalPairs = buildNeighborList<FPTYPE, POSVECTYPE>(nAtom, position, neighborList);
  std::cout << totalPairs << " of " << nAtom * maxNeighbors
            << " pairs within cutoff distance = "
            << 100.0 * ((double)totalPairs / (nAtom * maxNeighbors)) << " %\n";

  POSVECTYPE* d_position = nullptr;
  FORCEVECTYPE* d_force = nullptr;
  int* d_neighborList = nullptr;

  assert(cudaMalloc((void**)&d_position, nAtom * sizeof(POSVECTYPE)) == cudaSuccess);
  assert(cudaMalloc((void**)&d_force, nAtom * sizeof(FORCEVECTYPE)) == cudaSuccess);
  assert(cudaMalloc((void**)&d_neighborList, maxNeighbors * nAtom * sizeof(int)) == cudaSuccess);

  assert(cudaMemcpy(d_position, position, nAtom * sizeof(POSVECTYPE), cudaMemcpyHostToDevice) == cudaSuccess);
  assert(cudaMemcpy(d_neighborList, neighborList, maxNeighbors * nAtom * sizeof(int), cudaMemcpyHostToDevice) == cudaSuccess);

  md(d_position,
     d_force,
     d_neighborList,
     nAtom,
     maxNeighbors,
     lj1,
     lj2,
     cutsq);

  assert(cudaMemcpy(force, d_force, nAtom * sizeof(FORCEVECTYPE), cudaMemcpyDeviceToHost) == cudaSuccess);

  std::cout << "Performing Correctness Check (may take several minutes)\n";

  checkResults<FPTYPE, FORCEVECTYPE, POSVECTYPE>(force, position, neighborList, nAtom);

  auto start = std::chrono::steady_clock::now();

  for (int i = 0; iteration > i; i++) {
    md(d_position,
       d_force,
       d_neighborList,
       nAtom,
       maxNeighbors,
       lj1,
       lj2,
       cutsq);
  }

  auto end = std::chrono::steady_clock::now();
  auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
  std::cout << "Average kernel execution time " << (time * 1e-9f) / iteration << " (s)\n";

  assert(cudaFree(d_position) == cudaSuccess);
  assert(cudaFree(d_force) == cudaSuccess);
  assert(cudaFree(d_neighborList) == cudaSuccess);

  free(position);
  free(force);
  free(neighborList);

  return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <chrono>
#include <cuda_runtime.h>

#define _QUEENS_BLOCK_SIZE_   128
#define _EMPTY_      -1

typedef struct queen_root{
  unsigned int control;
  int8_t board[12];
} QueenRoot;

inline void prefixesHandleSol(QueenRoot *root_prefixes, unsigned int flag,
                              const int8_t *board, int initialDepth, unsigned long long num_sol)
{
  root_prefixes[num_sol].control = flag;
  for(int i = 0; i < initialDepth; ++i)
    root_prefixes[num_sol].board[i] = board[i];
}

inline bool MCstillLegal(const int8_t *board, const int r)
{
  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) return false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r - 1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) return false;
  }
  return true;
}

__device__ bool queens_stillLegal(const int8_t *board, const int r)
{
  bool safe = true;

  for (int i = 0; i < r; ++i)
    if (board[i] == board[r]) safe = false;

  int ld = board[r];
  int rd = board[r];
  for (int i = r - 1; i >= 0; --i) {
    --ld; ++rd;
    if (board[i] == ld || board[i] == rd) safe = false;
  }
  return safe;
}

__global__ void BP_queens_root_dfs_kernel(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict root_prefixes,
  unsigned long long *__restrict vector_of_tree_size,
  unsigned long long *__restrict sols)
{
  unsigned int idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (idx >= nPreFixos) return;

  unsigned int flag = 0;
  unsigned int bit_test = 0;
  int8_t vertice[20];
  int N_l = N;
  int i, depth;
  unsigned long long qtd_solutions_thread = 0ULL;
  int depthGlobal = depthPreFixos;
  unsigned long long tree_size = 0ULL;

#pragma unroll 2
  for (i = 0; i < N_l; ++i) {
    vertice[i] = _EMPTY_;
  }

  flag = root_prefixes[idx].control;

#pragma unroll 2
  for (i = 0; i < depthGlobal; ++i)
    vertice[i] = root_prefixes[idx].board[i];

  depth = depthGlobal;

  do {
    vertice[depth]++;
    bit_test = 0;
    bit_test |= (1u << vertice[depth]);
    if (vertice[depth] == N_l) {
      vertice[depth] = _EMPTY_;
    } else if (!(flag & bit_test) && queens_stillLegal(vertice, depth)) {
      ++tree_size;
      flag |= (1u << vertice[depth]);
      depth++;
      if (depth == N_l) {
        ++qtd_solutions_thread;
      } else continue;
    } else continue;
    depth--;
    flag &= ~(1u << vertice[depth]);
  } while (depth >= depthGlobal);

  sols[idx] = qtd_solutions_thread;
  vector_of_tree_size[idx] = tree_size;
}

void BP_queens_root_dfs(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict root_prefixes,
  unsigned long long *__restrict vector_of_tree_size,
  unsigned long long *__restrict sols)
{
  if (nPreFixos == 0) return;
  int threads = _QUEENS_BLOCK_SIZE_;
  int blocks = (nPreFixos + threads - 1) / threads;
  BP_queens_root_dfs_kernel<<<blocks, threads>>>(
    N, nPreFixos, depthPreFixos, root_prefixes, vector_of_tree_size, sols);
}

unsigned long long BP_queens_prefixes(int size, int initialDepth,
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes)
{
  unsigned int flag = 0;
  int bit_test = 0;
  int8_t vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0ULL;

  for (i = 0; i < size; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do {
    vertice[nivel]++;
    bit_test = 0;
    bit_test |= (1 << vertice[nivel]);

    if (vertice[nivel] == size) {
      vertice[nivel] = _EMPTY_;
    } else if (MCstillLegal(vertice, nivel) && !(flag & bit_test)) {
      flag |= (1u << vertice[nivel]);
      nivel++;
      ++local_tree;
      if (nivel == initialDepth) {
        prefixesHandleSol(root_prefixes, flag, vertice, initialDepth, num_sol);
        num_sol++;
      } else continue;
    } else continue;

    nivel--;
    flag &= ~(1u << vertice[nivel]);

  } while (nivel >= 0);

  *tree_size = local_tree;

  return num_sol;
}

void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  printf("\n### Regular BP-DFS search. ###\n");

  QueenRoot *root_prefixes_d = nullptr;
  unsigned long long *vector_of_tree_size_d = nullptr;
  unsigned long long *sols_d = nullptr;

  size_t prefixes_bytes = (size_t)n_explorers * sizeof(QueenRoot);
  size_t ull_bytes = (size_t)n_explorers * sizeof(unsigned long long);

  if (n_explorers > 0) {
    cudaMalloc((void**)&root_prefixes_d, prefixes_bytes);
    cudaMalloc((void**)&vector_of_tree_size_d, ull_bytes);
    cudaMalloc((void**)&sols_d, ull_bytes);
    cudaMemcpy(root_prefixes_d, root_prefixes_h, prefixes_bytes, cudaMemcpyHostToDevice);
  }

  cudaEvent_t start, stop;
  cudaEventCreate(&start);
  cudaEventCreate(&stop);

  cudaEventRecord(start);
  for (int i = 0; i < repeat; i++) {
    BP_queens_root_dfs(size,
                       n_explorers,
                       initial_depth,
                       root_prefixes_d,
                       vector_of_tree_size_d,
                       sols_d);
  }
  cudaEventRecord(stop);
  cudaEventSynchronize(stop);

  float ms = 0.0f;
  cudaEventElapsedTime(&ms, start, stop);
  printf("Average kernel execution time: %f (s)\n", (ms * 1e-3f) / repeat);

  if (n_explorers > 0) {
    cudaMemcpy(vector_of_tree_size_h, vector_of_tree_size_d, ull_bytes, cudaMemcpyDeviceToHost);
    cudaMemcpy(sols_h, sols_d, ull_bytes, cudaMemcpyDeviceToHost);
  }

  cudaEventDestroy(start);
  cudaEventDestroy(stop);

  if (root_prefixes_d) cudaFree(root_prefixes_d);
  if (vector_of_tree_size_d) cudaFree(vector_of_tree_size_d);
  if (sols_d) cudaFree(sols_d);
}

int main(int argc, char *argv[])
{
  if (argc != 4) {
    printf("Usage: %s <size> <initial depth> <repeat>\n", argv[0]);
    return 1;
  }
  const short size = atoi(argv[1]);
  const int initialDepth = atoi(argv[2]);
  const int repeat = atoi(argv[3]);
  printf("\n### Initial depth: %d - Size: %d:", initialDepth, size);

  unsigned long long tree_size = 0ULL;
  unsigned long long qtd_sols_global = 0ULL;
  unsigned int nMaxPrefixos = 75580635;

  QueenRoot* root_prefixes_h = (QueenRoot*)malloc(sizeof(QueenRoot) * (size_t)nMaxPrefixos);
  unsigned long long *vector_of_tree_size_h = (unsigned long long*)malloc(sizeof(unsigned long long) * (size_t)nMaxPrefixos);
  unsigned long long *solutions_h = (unsigned long long*)malloc(sizeof(unsigned long long) * (size_t)nMaxPrefixos);

  if (root_prefixes_h == NULL || vector_of_tree_size_h == NULL || solutions_h == NULL) {
    printf("Error: host out of memory\n");
    if (root_prefixes_h) free(root_prefixes_h);
    if (vector_of_tree_size_h) free(vector_of_tree_size_h);
    if (solutions_h) free(solutions_h);
    return 1;
  }

  unsigned long long n_explorers = BP_queens_prefixes(size, initialDepth, &tree_size, root_prefixes_h);

  nqueens(size, initialDepth, (unsigned int)n_explorers, root_prefixes_h, vector_of_tree_size_h, solutions_h, repeat);

  printf("\nTree size: %llu", tree_size);

  for (unsigned long long i = 0; i < n_explorers; ++i) {
    if (solutions_h[i] > 0)
      qtd_sols_global += solutions_h[i];
    if (vector_of_tree_size_h[i] > 0)
      tree_size += vector_of_tree_size_h[i];
  }

  printf("\nNumber of solutions found: %llu \nTree size: %llu\n", qtd_sols_global, tree_size);

  if (size == 15 && initialDepth == 7) {
    if (qtd_sols_global == 2279184 && tree_size == 171129071)
      printf("PASS\n");
    else
      printf("FAIL\n");
  }

  free(root_prefixes_h);
  free(vector_of_tree_size_h);
  free(solutions_h);
  return 0;
}

