void BP_queens_root_dfs(
  int N, unsigned int nPreFixos, int depthPreFixos,
  const QueenRoot *__restrict d_root_prefixes,
  unsigned long long *__restrict d_vector_of_tree_size,
  unsigned long long *__restrict d_sols)
{
  if (nPreFixos == 0) return;

  unsigned int blocks = (nPreFixos + _QUEENS_BLOCK_SIZE_ - 1) / _QUEENS_BLOCK_SIZE_;
  BP_queens_root_dfs_kernel<<<blocks, _QUEENS_BLOCK_SIZE_>>>(
      N, nPreFixos, depthPreFixos, d_root_prefixes, d_vector_of_tree_size, d_sols);
}

unsigned long long BP_queens_prefixes(int size, int initialDepth,
                                      unsigned long long *tree_size,
                                      QueenRoot *root_prefixes)
{
  unsigned int flag = 0;
  int bit_test = 0;
  int8_t vertice[20];
  int i, nivel;
  unsigned long long local_tree = 0ULL;
  unsigned long long num_sol = 0;

  for (i = 0; size > i; ++i) {
    vertice[i] = -1;
  }

  nivel = 0;

  do {

    vertice[nivel]++;
    bit_test = 0;
    bit_test = bit_test | (1 << vertice[nivel]);

    if (vertice[nivel] == size) {
      vertice[nivel] = _EMPTY_;
    } else if (MCstillLegal(vertice, nivel) && !(flag & bit_test)) {

      flag |= (1u << vertice[nivel]);
      nivel++;
      ++local_tree;
      if (nivel == initialDepth) {
        prefixesHandleSol(root_prefixes, flag, vertice, initialDepth, num_sol);
        num_sol++;
      } else continue;
    } else continue;

    nivel--;
    flag = flag & (~(1u << vertice[nivel]));

  } while (nivel >= 0);

  *tree_size = local_tree;

  return num_sol;
}

void nqueens(short size, int initial_depth, unsigned int n_explorers, QueenRoot *root_prefixes_h,
             unsigned long long *vector_of_tree_size_h, unsigned long long *sols_h, const int repeat)
{
  printf("\n### Regular BP-DFS search. ###\n");

  if (repeat <= 0) {
    printf("Average kernel execution time: %f (s)\n", 0.0f);
    return;
  }

  QueenRoot *d_root_prefixes = nullptr;
  unsigned long long *d_vector_of_tree_size = nullptr;
  unsigned long long *d_sols = nullptr;

  size_t prefixes_bytes = (size_t)n_explorers * sizeof(QueenRoot);
  size_t ull_bytes = (size_t)n_explorers * sizeof(unsigned long long);

  if (n_explorers > 0) {
    CHECK_CUDA(cudaMalloc((void **)&d_root_prefixes, prefixes_bytes));
    CHECK_CUDA(cudaMalloc((void **)&d_vector_of_tree_size, ull_bytes));
    CHECK_CUDA(cudaMalloc((void **)&d_sols, ull_bytes));
    CHECK_CUDA(cudaMemcpy(d_root_prefixes, root_prefixes_h, prefixes_bytes, cudaMemcpyHostToDevice));
  }

  cudaEvent_t start, stop;
  CHECK_CUDA(cudaEventCreate(&start));
  CHECK_CUDA(cudaEventCreate(&stop));

  CHECK_CUDA(cudaEventRecord(start));
  for (int i = 0; repeat > i; i++) {
    BP_queens_root_dfs(size,
                       n_explorers,
                       initial_depth,
                       d_root_prefixes,
                       d_vector_of_tree_size,
                       d_sols);
  }
  CHECK_CUDA(cudaEventRecord(stop));
  CHECK_CUDA(cudaEventSynchronize(stop));
  CHECK_CUDA(cudaGetLastError());

  float ms = 0.0f;
  CHECK_CUDA(cudaEventElapsedTime(&ms, start, stop));
  printf("Average kernel execution time: %f (s)\n", (ms * 1e-3f) / repeat);

  if (n_explorers > 0) {
    CHECK_CUDA(cudaMemcpy(vector_of_tree_size_h, d_vector_of_tree_size, ull_bytes, cudaMemcpyDeviceToHost));
    CHECK_CUDA(cudaMemcpy(sols_h, d_sols, ull_bytes, cudaMemcpyDeviceToHost));
  }

  CHECK_CUDA(cudaEventDestroy(start));
  CHECK_CUDA(cudaEventDestroy(stop));

  if (d_root_prefixes) CHECK_CUDA(cudaFree(d_root_prefixes));
  if (d_vector_of_tree_size) CHECK_CUDA(cudaFree(d_vector_of_tree_size));
  if (d_sols) CHECK_CUDA(cudaFree(d_sols));
}

