int *random_pages(int n, unsigned int *noutlinks, int divisor) {
  int i, j, k;
  int *pages = (int *)malloc((size_t)n * n * sizeof(int));

  if (divisor <= 0) {
    fprintf(stderr,
            "ERROR: Invalid divisor '%d' for random initialization, divisor "
            "should be greater or equal to 1\n",
            divisor);
    exit(1);
  }

  for (i = 0; i < n; ++i) {
    noutlinks[i] = 0;
    for (j = 0; j < n; ++j) {
      if (i != j && (abs(rand()) % divisor == 0)) {
        pages[(size_t)i * n + j] = 1;
        noutlinks[i] += 1;
      }
    }

    if (noutlinks[i] == 0) {
      do {
        k = abs(rand()) % n;
      } while (k == i);
      pages[(size_t)i * n + k] = 1;
      noutlinks[i] = 1;
    }
  }
  return pages;
}

void init_array(float *a, int n, float val) {
  int i;
  for (i = 0; i < n; ++i) {
    a[i] = val;
  }
}

void usage(char *argv[]) {
  fprintf(stderr,
          "Usage: %s [-n number of pages] [-i max iterations]"
          " [-t threshold] [-q divsor for zero density]\n",
          argv[0]);
}

