    {0, 0, 0}};

float maximum_dif(float *difs, int n) {
  int i;
  float max = 0.0f;
  for (i = 0; i < n; ++i) {
    max = difs[i] > max ? difs[i] : max;
  }
  return max;
}

__global__ void map_kernel(const int *__restrict__ pages,
                           const float *__restrict__ page_ranks,
                           float *__restrict__ maps,
                           const unsigned int *__restrict__ noutlinks, int n) {
  int i = blockIdx.x * blockDim.x + threadIdx.x;
  if (i < n) {
    float outbound_rank = page_ranks[i] / (float)noutlinks[i];
    size_t base = (size_t)i * (size_t)n;
    for (int j = 0; j < n; ++j) {
      maps[base + (size_t)j] = pages[base + (size_t)j] * outbound_rank;
    }
  }
}

__global__ void reduce_kernel(float *__restrict__ page_ranks,
                              const float *__restrict__ maps, int n,
                              float *__restrict__ diffs) {
  int j = blockIdx.x * blockDim.x + threadIdx.x;
  if (j < n) {
    float old_rank = page_ranks[j];
    float new_rank = 0.0f;
    for (int i = 0; i < n; ++i) {
      new_rank += maps[(size_t)i * (size_t)n + (size_t)j];
    }
    new_rank = ((1.f - D_FACTOR) / n) + (D_FACTOR * new_rank);
    diffs[j] = fmaxf(fabsf(new_rank - old_rank), diffs[j]);
    page_ranks[j] = new_rank;
  }
}

