  CUDA_CHECK(cudaMalloc((void **)&d_noutlinks, link_size));
  CUDA_CHECK(cudaMalloc((void **)&d_diffs, rank_size));

  CUDA_CHECK(
      cudaMemcpy(d_pages, pages, pages_size, cudaMemcpyHostToDevice));
  CUDA_CHECK(cudaMemcpy(d_page_ranks, page_ranks, rank_size,
                        cudaMemcpyHostToDevice));
  CUDA_CHECK(cudaMemcpy(d_noutlinks, noutlinks, link_size,
                        cudaMemcpyHostToDevice));
  CUDA_CHECK(
      cudaMemcpy(d_diffs, diffs, rank_size, cudaMemcpyHostToDevice));

  for (t = 1; t <= iter && max_diff >= thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    map_kernel<<<grid_size, block_size>>>(d_pages, d_page_ranks, d_maps,
                                          d_noutlinks, n);
    reduce_kernel<<<grid_size, block_size>>>(d_page_ranks, d_maps, n, d_diffs);
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    auto end = std::chrono::high_resolution_clock::now();
    ktime +=
        std::chrono::duration_cast<std::chrono::duration<double>>(end - start)
            .count();

    CUDA_CHECK(
        cudaMemcpy(diffs, d_diffs, rank_size, cudaMemcpyDeviceToHost));
    max_diff = maximum_dif(diffs, n);
  }

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff,
          t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf "
         "(s)\n",
         n, iter, thresh, ktime);

  CUDA_CHECK(cudaFree(d_pages));
  CUDA_CHECK(cudaFree(d_maps));
  CUDA_CHECK(cudaFree(d_page_ranks));
  CUDA_CHECK(cudaFree(d_noutlinks));
  CUDA_CHECK(cudaFree(d_diffs));

  memset(diffs, 0, rank_size);
  for (t = 1; t <= iter && max_diff_ref >= thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);
  return 0;
}

