  cuda_check(cudaMemcpy(d_page_ranks, page_ranks, rank_size, cudaMemcpyHostToDevice), "cudaMemcpy(d_page_ranks)");
  cuda_check(cudaMemcpy(d_noutlinks, noutlinks, link_size, cudaMemcpyHostToDevice), "cudaMemcpy(d_noutlinks)");
  cuda_check(cudaMemcpy(d_diffs, diffs, rank_size, cudaMemcpyHostToDevice), "cudaMemcpy(d_diffs)");

  double ktime = 0.0;
  dim3 block((unsigned int)block_size);
  dim3 grid((unsigned int)((n + (int)block_size - 1) / (int)block_size));

  for (t = 1; t <= iter && max_diff >= thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    map_kernel<<<grid, block>>>(d_pages, d_page_ranks, d_maps, d_noutlinks, n);
    cuda_check(cudaGetLastError(), "map_kernel launch");

    reduce_kernel<<<grid, block>>>(d_page_ranks, d_maps, n, d_diffs);
    cuda_check(cudaGetLastError(), "reduce_kernel launch");

    cuda_check(cudaDeviceSynchronize(), "cudaDeviceSynchronize");

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double> >(end - start).count();

    cuda_check(cudaMemcpy(diffs, d_diffs, rank_size, cudaMemcpyDeviceToHost), "cudaMemcpy(diffs)");
    max_diff = maximum_dif(diffs, n);
